using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = "";

    [LoadColumn(1)]
    public string Description { get; set; } = "";

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = "";
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = "";

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = "";
    public string Description { get; set; } = "";
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = "";
    public Dictionary<string, float> Confidence { get; set; } = new();
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly ILogger<TicketClassifierService> _logger;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(ILogger<TicketClassifierService> logger)
    {
        _logger = logger;
        _mlContext = new MLContext(seed: 0);

        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        _model = TrainModel(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract the category labels in score-array order
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        _model.GetOutputSchema(dataView.Schema)["Score"]
            .GetSlotNames(ref labelBuffer);
        _categoryLabels = labelBuffer.DenseValues()
            .Select(v => v.ToString()).ToArray();

        EvaluateModel(dataView);
    }

    private ITransformer TrainModel(IDataView data)
    {
        // Combine text features and numeric priority into a single feature vector
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(data);
        _logger.LogInformation("Model training complete.");
        return model;
    }

    private void EvaluateModel(IDataView data)
    {
        var predictions = _model.Transform(data);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("Log Loss Reduction: {LogLossReduction:F4}", metrics.LogLossReduction);
        _logger.LogInformation("================================");
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _categoryLabels.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly TicketClassifierService _classifierService;

    public TicketController(TicketClassifierService classifierService)
    {
        _classifierService = classifierService;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var result = _classifierService.Predict(request);
        return Ok(result);
    }
}

